namespace sv_b1395c9ecab74a9c96068e64981b0cf5.Services;

public record Recipe(int Id, string Title, string Description, int PrepTimeMinutes);

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Spaghetti Carbonara", "Creamy Roman pasta with guanciale, egg yolk, and Pecorino Romano.", 25),
            new(3, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream and cocoa.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken pieces in a rich, spiced tomato-cream sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach curry with cubes of soft paneer cheese.", 35),
            new(6, "Biryani", "Fragrant layered rice dish with aromatic spices and tender meat.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Sushi Rolls", "Fresh fish and vegetables wrapped in seasoned rice and nori.", 40),
            new(8, "Ramen", "Rich pork bone broth with handmade noodles, egg, and chashu.", 55),
            new(9, "Tempura", "Light and crispy battered vegetables and shrimp.", 20),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@using sv_b1395c9ecab74a9c96068e64981b0cf5.Services
@rendermode InteractiveServer
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <ul>
        @foreach (var recipe in DisplayRecipes)
        {
            <li>
                <strong>@recipe.Title</strong> — @recipe.Description
                <span class="text-muted">(@recipe.PrepTimeMinutes min)</span>
            </li>
        }
    </ul>
}

@code {
    [Parameter] public int CuisineId { get; set; }
    [SupplyParameterFromQuery(Name = "sort")] public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayRecipes => Sort?.ToLowerInvariant() switch
    {
        "newest" => _recipes!.OrderByDescending(r => r.Id),
        "popular" => _recipes!.OrderBy(r => r.PrepTimeMinutes),
        _ => _recipes!
    };

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }
        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        var targetCuisineId = CuisineId;
        _error = null;

        if (_recipes is not null)
        {
            _isRefreshing = true;
        }

        try
        {
            var results = await RecipeService.GetByCuisineAsync(targetCuisineId, token);
            _recipes = results;
            _loadedCuisineId = targetCuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was superseded; do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", targetCuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", targetCuisineId);
            _error = "Something went wrong loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private Task Retry() => LoadRecipesAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

